from sqlalchemy import create_engine, Column, Integer, String, Float, DateTime, ForeignKey
from sqlalchemy.ext.declarative import declarative_base
from sqlalchemy.orm import sessionmaker, relationship
from datetime import datetime

engine = create_engine('sqlite:///wheelshop.db')
Base = declarative_base()

class Bicycle(Base):
    __tablename__ = 'bicycles'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    price = Column(Float)
    description = Column(String)
    created_at = Column(DateTime, default=datetime.utcnow)
    spare_parts = relationship('SparePart', backref='bicycle')
    supplements = relationship('Supplement', backref='bicycle')

class SparePart(Base):
    __tablename__ = 'spare_parts'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    price = Column(Float)
    description = Column(String)
    created_at = Column(DateTime, default=datetime.utcnow)
    bicycle_id = Column(Integer, ForeignKey('bicycles.id'))

class Supplement(Base):
    __tablename__ = 'supplements'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    price = Column(Float)
    description = Column(String)
    created_at = Column(DateTime, default=datetime.utcnow)
    bicycle_id = Column(Integer, ForeignKey('bicycles.id'))

Base.metadata.create_all(engine)

Session = sessionmaker(bind=engine)
session = Session()

def add_bicycle(name, price, description):
    bicycle = Bicycle(name=name, price=price, description=description)
    session.add(bicycle)
    session.commit()

def add_spare_part(name, price, description, bicycle_id):
    spare_part = SparePart(name=name, price=price, description=description, bicycle_id=bicycle_id)
    session.add(spare_part)
    session.commit()

def add_supplement(name, price, description, bicycle_id):
    supplement = Supplement(name=name, price=price, description=description, bicycle_id=bicycle_id)
    session.add(supplement)
    session.commit()

def get_bicycles():
    return session.query(Bicycle).all()

def get_spare_parts(bicycle_id):
    return session.query(SparePart).filter_by(bicycle_id=bicycle_id).all()

def get_supplements(bicycle_id):
    return session.query(Supplement).filter_by(bicycle_id=bicycle_id).all()

