    bicycle = session.query(Bicycle).filter_by(id=id).first()
    if bicycle:
        bicycle.name = name
        bicycle.price = price
        bicycle.description = description
        session.commit()

def update_spare_part(id, name, price, description):
    spare_part = session.query(SparePart).filter_by(id=id).first()
    if spare_part:
        spare_part.name = name
        spare_part.price = price
        spare_part.description = description
        session.commit()

def update_supplement(id, name, price, description):
    supplement = session.query(Supplement).filter_by(id=id).first()
    if supplement:
        supplement.name = name
        supplement.price = price
        supplement.description = description
        session.commit()

def delete_bicycle(id):
    bicycle = session.query(Bicycle).filter_by(id=id).first()
    if bicycle:
        session.delete(bicycle)
        session.commit()

def delete_spare_part(id):
    spare_part = session.query(SparePart).filter_by(id=id).first()
    if spare_part:
        session.delete(spare_part)
        session.commit()

def delete_supplement(id):
