engine = create_engine('sqlite:///bike_shop.db')
Base = declarative_base()

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)
    price = Column(Float)
    category_id = Column(Integer, ForeignKey('categories.id'))
    category = relationship("Category", backref="products")

class Order(Base):
    __tablename__ = 'orders'
    id = Column(Integer, primary_key=True)
    customer_name = Column(String)
    total = Column(Float)

class OrderItem(Base):
    __tablename__ = 'order_items'
    id = Column(Integer, primary_key=True)
    order_id = Column(Integer, ForeignKey('orders.id'))
    product_id = Column(Integer, ForeignKey('products.id'))
    quantity = Column(Integer)
    order = relationship("Order", backref="items")
    product = relationship("Product", backref="orders")

Base.metadata.create_all(engine)

Session = sessionmaker(bind=engine)
session = Session()

def add_category(name):
    category = Category(name=name)
    session.add(category)
    session.commit()

def add_product(name, description, price, category_id):
    product = Product(name=name, description=description, price=price, category_id=category_id)
    session.add(product)
    session.commit()

def add_order(customer_name, total):
    order = Order(customer_name=customer_name, total=total)
    session.add(order)
    session.commit()

def add_order_item(order_id, product_id, quantity):
    order_item = OrderItem(order_id=order_id, product_id=product_id, quantity=quantity)
    session.add(order_item)
    session.commit()

def delete_category(id):
    category = session.query(Category).filter_by(id=id).first()
    session.delete(category)
    session.commit()

def delete_product(id):
    product = session.query(Product).filter_by(id=id).first()
    session.delete(product)
    session.commit()

def delete_order(id):
    order = session.query(Order).filter_by(id=id).first()
    session.delete(order)
    session.commit()

def delete_order_item(id):
    order_item = session.query(OrderItem).filter_by(id=id).first()
    session.delete(order_item)
    session.commit()

def update_category(id, name):
    category = session.query(Category).filter_by(id=id).first()
    category.name = name
    session.commit()

def update_product(id, name, description, price, category_id):
    product = session.query(Product).filter_by(id=id).first()
    product.name = name
    product.description = description
    product.price = price
    product.category_id = category_id
    session.commit()

def update_order(id, customer_name, total):
    order = session.query(Order).filter_by(id=id).first()
    order.customer_name = customer_name
    order.total = total
    session.commit()

def update_order_item(id, order_id, product_id, quantity):
    order_item = session.query(OrderItem).filter_by(id=id).first()
    order_item.order_id = order_id
    order_item.product_id = product_id
